{
  "name": "unintended_bias_metrics",
  "full_name": "Nuanced Metrics for Measuring Unintended Bias Against Identity Groups",
  "source_url": "https://git.io/fhpcC",
  "paper_url": "https://arxiv.org/abs/1903.04561",
  "year": 2019,
  "domain": "Toxicity detection / unintended bias measurement in text classifiers",
